/**
 * Schemagen tests: resource annotations
 *
 * Covers the five annotation modes generated by generateResources.ts:
 *   - fungible: true  → add / sub generated
 *   - unique: true    → mint with auto-id generated; existence checks
 *   - reactive: true  → set_reactive / set_<field>_reactive generated
 *   - transferable: true + objects/scenes.accepts → transfer_* functions
 *   - listable: true  → list / cancel_listing / expire_listing generated
 */

import { describe, it, afterAll } from 'vitest';
import {
  runSchemaGen,
  cleanupDir,
  readGenerated,
  assertContains,
  assertNotContains,
  defineConfig
} from './helpers.js';

describe('Schemagen: resource annotations', () => {
  const temps: string[] = [];

  afterAll(() => temps.forEach(cleanupDir));

  // ── fungible: true ───────────────────────────────────────────────────────────

  it('fungible: true — generates add_<name> and sub_<name> instead of bare set', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        gold: { fields: { amount: 'u64' }, fungible: true }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'gold.move');
    assertContains(content, 'public(package) fun add(');
    assertContains(content, 'public(package) fun sub(');
  });

  // ── unique: true ─────────────────────────────────────────────────────────────

  it('unique: true + keys — generates mint with auto-generated item_id', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        weapon: {
          fields: { item_id: 'u64', damage: 'u32', rarity: 'u8' },
          unique: true,
          keys: ['item_id']
        }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'weapon.move');
    assertContains(content, 'public(package) fun mint(');
    // mint should auto-generate an item_id using a counter/nonce
    assertContains(content, 'item_id');
  });

  // ── reactive: true ───────────────────────────────────────────────────────────

  it('reactive: true (struct resource) — generates set_reactive and per-field variants', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        hp: {
          fields: { current: 'u64', max: 'u64' },
          reactive: true
        }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'hp.move');
    assertContains(content, 'public(package) fun set_reactive(');
    assertContains(content, 'public(package) fun set_current_reactive(');
    assertContains(content, 'public(package) fun set_max_reactive(');
    // Reactive uses SceneMetadata
    assertContains(content, 'SceneMetadata');
    assertContains(content, 'set_record_reactive');
  });

  it('reactive: true (primitive resource) — generates per-field set_<field>_reactive', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        score: { fields: { value: 'u64' }, reactive: true }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'score.move');
    assertContains(content, 'set_value_reactive');
    assertContains(content, 'SceneMetadata');
    assertContains(content, 'set_field_reactive');
  });

  // ── reactive: true + keys ────────────────────────────────────────────────────

  it('reactive: true + keys — generates keyed set_reactive and per-field variants', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        buff: {
          fields: { player: 'address', value: 'u32' },
          keys: ['player'],
          reactive: true
        }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'buff.move');
    // Only 1 non-key value field → per-field variant only (no full set_reactive)
    assertContains(content, 'set_value_reactive');
    // Key parameter appears in reactive function signatures
    assertContains(content, 'player: address');
    assertContains(content, 'set_field_reactive');
    assertNotContains(content, 'public(package) fun set_reactive(');
  });

  // ── transferable: true (fungible) + objects.accepts ──────────────────────────

  it('transferable fungible resource accepted by an object — generates transfer_user_to_<obj> and transfer_<obj>_to_user', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        gold: { fields: { amount: 'u64' }, fungible: true, transferable: true }
      },
      objects: {
        guild: { fields: { level: 'u32' }, accepts: ['gold'] }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'gold.move');
    assertContains(content, 'transfer_user_to_guild');
    assertContains(content, 'transfer_guild_to_user');
  });

  it('transferable fungible resource accepted by a scene — generates transfer_user_to_<scene> and transfer_<scene>_to_user', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        loot: { fields: { amount: 'u64' }, fungible: true, transferable: true }
      },
      scenes: {
        dungeon_run: { fields: { floor: 'u32' }, accepts: ['loot'] }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'loot.move');
    assertContains(content, 'transfer_user_to_dungeon_run');
    assertContains(content, 'transfer_dungeon_run_to_user');
  });

  // ── transferable: true (unique) + objects.accepts ────────────────────────────

  it('transferable unique resource accepted by an object — generates transfer_user_to_<obj> and transfer_<obj>_to_user', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        weapon: {
          fields: { item_id: 'u64', damage: 'u32' },
          unique: true,
          keys: ['item_id'],
          transferable: true
        }
      },
      objects: {
        guild: { fields: { level: 'u32' }, accepts: ['weapon'] }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'weapon.move');
    assertContains(content, 'transfer_user_to_guild');
    assertContains(content, 'transfer_guild_to_user');
  });

  // ── listable: true ───────────────────────────────────────────────────────────

  it('listable: true (unique) — generates list, cancel_listing, expire_listing entry fns', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        sword: {
          fields: { item_id: 'u64', power: 'u32' },
          unique: true,
          keys: ['item_id'],
          listable: true
        }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'sword.move');
    // entry functions are named without the resource suffix (inside the sword module)
    assertContains(content, 'public entry fun list(');
    assertContains(content, 'public entry fun cancel_listing(');
    assertContains(content, 'public entry fun expire_listing(');
    assertContains(content, 'take_record');
    assertContains(content, 'restore_record');
  });

  it('listable: true (fungible) — generates list entry with amount parameter', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        gold: {
          fields: { amount: 'u64' },
          fungible: true,
          listable: true
        }
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'gold.move');
    assertContains(content, 'public entry fun list(');
    // fungible listing includes an amount parameter
    assertContains(content, 'amount');
  });

  // ── No annotations: none of the above generated ──────────────────────────────

  it('plain resource without annotations — no add/sub/mint/reactive/transfer/list generated', async () => {
    const config = defineConfig({
      name: 'mygame',
      description: 'test',
      resources: {
        score: 'u32'
      }
    });

    const { tempDir, codegenDir } = await runSchemaGen(config);
    temps.push(tempDir);

    const content = readGenerated(codegenDir, 'resources', 'score.move');
    assertNotContains(content, 'fun add(');
    assertNotContains(content, 'fun sub(');
    assertNotContains(content, 'fun mint(');
    assertNotContains(content, 'set_reactive');
    assertNotContains(content, 'transfer_user_to_');
    assertNotContains(content, 'list_score');
  });
});
